def execute_calculation_string(calc_expr: str, var_dict: dict) -> str:
    """
    Substitute variables in calc_expr using var_dict and evaluate the resulting arithmetic expression.
    Returns the computed result as a string.
    Raises ValueError if input is invalid or computation fails.
    """
    if not isinstance(calc_expr, str):
        raise ValueError("calc_expr must be a string")
    if var_dict is None:
        var_dict = {}

    expr = calc_expr.strip()
    if expr == "":
        return ""

    try:
        substituted = substitute_variables(expr, var_dict)
    except Exception as e:
        raise ValueError(f"Failed to substitute variables: {e}")

    try:
        return evaluate_expression(substituted)
    except Exception as e:
        raise ValueError(f"Failed to evaluate expression: {e}")

